/**
 * Admin Page Editor
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import { useState, useEffect } from 'react';
import { useParams } from 'next/navigation';

interface PageData {
  id: string;
  title: string;
  slug: string;
  status: 'published' | 'draft';
  language: 'en' | 'ar';
  sections: Section[];
}

interface Section {
  id: string;
  type: string;
  title: string;
  description: string;
  order: number;
}

export default function PageEditor() {
  const params = useParams();
  const [page, setPage] = useState<PageData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const fetchPage = async () => {
      try {
        const token = localStorage.getItem('adminToken');
        if (!token) {
          setIsLoading(false);
          return;
        }

        const response = await fetch(`/api/admin/pages/${params.id}`, {
          headers: {
            'Authorization': `Bearer ${token}`,
          },
        });

        if (response.ok) {
          const data = await response.json();
          setPage(data.page);
        } else {
          console.error('Failed to fetch page');
        }
      } catch (error) {
        console.error('Error fetching page:', error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchPage();
  }, [params.id]);

  const handleSectionUpdate = (sectionId: string, field: string, value: string) => {
    if (!page) return;
    
    setPage({
      ...page,
      sections: page.sections.map(section =>
        section.id === sectionId
          ? { ...section, [field]: value }
          : section
      ),
    });
  };

  const handleSave = async () => {
    if (!page) return;
    
    setIsSaving(true);
    try {
      const token = localStorage.getItem('adminToken');
      if (!token) return;

      const response = await fetch(`/api/admin/pages/${page.id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          title: page.title,
          status: page.status,
          sections: page.sections,
        }),
      });

      if (response.ok) {
        alert('Page saved successfully!');
      } else {
        alert('Failed to save page');
      }
    } catch (error) {
      console.error('Save error:', error);
      alert('Failed to save page');
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600 dark:text-gray-400">Loading page...</p>
        </div>
      </div>
    );
  }

  if (!page) {
    return (
      <div className="text-center py-12">
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Page not found</h1>
      </div>
    );
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            Edit Page: {page.title}
          </h1>
          <p className="mt-2 text-gray-600 dark:text-gray-400">
            {page.slug} • {page.language.toUpperCase()}
          </p>
        </div>
        
        <div className="flex space-x-3">
          <button
            onClick={handleSave}
            disabled={isSaving}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition-colors disabled:opacity-50"
          >
            {isSaving ? 'Saving...' : 'Save Changes'}
          </button>
          
          <a
            href={page.slug}
            target="_blank"
            rel="noopener noreferrer"
            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors"
          >
            Preview
          </a>
        </div>
      </div>

      {/* Page Settings */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6 mb-6">
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4">
          Page Settings
        </h2>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Page Title
            </label>
            <input
              type="text"
              value={page.title}
              onChange={(e) => setPage({ ...page, title: e.target.value })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
            />
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Status
            </label>
            <select
              value={page.status}
              onChange={(e) => setPage({ ...page, status: e.target.value as 'published' | 'draft' })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
            >
              <option value="draft">Draft</option>
              <option value="published">Published</option>
            </select>
          </div>
        </div>
      </div>

      {/* Sections */}
      <div className="space-y-6">
        <h2 className="text-xl font-bold text-gray-900 dark:text-white">
          Page Sections
        </h2>
        
        {page.sections.map((section) => (
          <div key={section.id} className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-3">
                <span className="px-2 py-1 text-xs font-medium rounded-full bg-blue-100 text-blue-800 dark:bg-blue-900/20 dark:text-blue-400">
                  {section.type}
                </span>
                <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                  Section {section.order}
                </h3>
              </div>
              
              <div className="flex space-x-2">
                <button className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                  ↑
                </button>
                <button className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                  ↓
                </button>
                <button className="text-red-400 hover:text-red-600">
                  ✕
                </button>
              </div>
            </div>
            
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Title
                </label>
                <input
                  type="text"
                  value={section.title}
                  onChange={(e) => handleSectionUpdate(section.id, 'title', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Description
                </label>
                <textarea
                  value={section.description}
                  onChange={(e) => handleSectionUpdate(section.id, 'description', e.target.value)}
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                />
              </div>
            </div>
          </div>
        ))}
        
        <button className="w-full border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-8 text-center hover:border-blue-400 dark:hover:border-blue-500 transition-colors">
          <div className="text-4xl mb-2">➕</div>
          <p className="text-gray-600 dark:text-gray-400 font-medium">
            Add New Section
          </p>
        </button>
      </div>
    </div>
  );
}